class Solution:
    def getMaximumXor(self, nums, maximumBit):
        mask = (1 << maximumBit) - 1
        cur = list(nums)
        res = []
        while cur:
            x = 0
            for v in cur:
                x ^= v
            res.append(x ^ mask)
            cur.pop()
        return res

