class Solution:
    def getMaximumXor(self, nums, maximumBit):
        mask = (1 << maximumBit) - 1
        x = 0
        for v in nums:
            x ^= v
        res = []
        for v in reversed(nums):
            res.append(x ^ mask)
            x ^= v
        return res

