var getMaximumXor = function(nums, maximumBit) {
    const mask = (1 << maximumBit) - 1;
    let x = 0;
    for (const v of nums) x ^= v;
    const res = [];
    for (let i = nums.length - 1; i >= 0; i--) {
        res.push(x ^ mask);
        x ^= nums[i];
    }
    return res;
};
